// Tweet count event: Elon Musk April 14-21, 2026
// Window: April 14 12:00 PM ET (16:00 UTC) to April 21 12:00 PM ET (16:00 UTC)
// Current count: 210, ~7.37 hours remaining

const THRESHOLD = 0.04;

const windowStart = new Date("2026-04-14T16:00:00Z").getTime();
const windowEnd   = new Date("2026-04-21T16:00:00Z").getTime();

const model = ctx.helpers.countModel({
  observed: ctx.news.totalCount,
  windowStart,
  windowEnd,
  nowTs: ctx.timing.nowTs,
});

// Log model info for diagnostics
const diagnostics = {
  observed: ctx.news.totalCount,
  projectedMu: model.mu,
  projectedSigma: model.sigma,
  rate: model.rate,
  elapsed: model.elapsed,
  remaining: model.remaining,
  elapsedPct: (model.elapsed / (model.elapsed + model.remaining) * 100).toFixed(1) + "%",
};

return ctx.markets.map((market) => {
  try {
    if (market.closed || market.hoursToExpiry < 0) {
      return { question: market.question, decision: "hold", reason: "closed or expired" };
    }
    const mCtx = { market, timing: ctx.timing };

    let pYes;
    if (market.questionType === "count" && market.strike !== null) {
      pYes = ctx.helpers.countRangeProb(model, market.strike, market.strike2);
    } else {
      pYes = 0.5;
    }

    const probs = ctx.helpers.binaryProbsFromYesProb(mCtx, pYes);
    const edges = ctx.helpers.edgeFromProbs(probs, mCtx);
    const best = edges[0].edge >= edges[1].edge ? edges[0] : edges[1];

    const result = {
      question: market.question,
      range: `${market.strike}-${market.strike2}`,
      pYes: +pYes.toFixed(4),
      marketYesPrice: market.outcomes[0].price,
      decision: best.edge < THRESHOLD ? "hold" : "buy",
      edge: +best.edge.toFixed(4),
      diagnostics: market.slug.includes("200-219") || market.slug.includes("220-239") || market.slug.includes("240-259") ? diagnostics : undefined,
    };

    if (best.edge >= THRESHOLD) {
      result.side = best.label;
      result.fairPrice = best.fairPrice;
      result.marketPrice = best.marketPrice;
    }

    return result;
  } catch (err) {
    return { question: market.question, decision: "hold", reason: String(err) };
  }
});
